import { User, Account, NewsArticle, NewsComment, NewsAiUsage } from '../types.ts';
import { supabase } from './supabase.ts';

const STORAGE_KEYS = {
  CURRENT_USER: 'ecokid_current_user'
};

export const db = {
  getCurrentUser: (): User | null => {
    try {
      const user = localStorage.getItem(STORAGE_KEYS.CURRENT_USER);
      return user ? JSON.parse(user) : null;
    } catch {
      return null;
    }
  },

  setCurrentUser: (user: User | null) => {
    if (user) {
      localStorage.setItem(STORAGE_KEYS.CURRENT_USER, JSON.stringify(user));
    } else {
      localStorage.removeItem(STORAGE_KEYS.CURRENT_USER);
    }
  },

  getUsers: async (): Promise<User[]> => {
    // 번호(number) 순으로 정렬하여 가져옴 (요청 4 반영)
    const { data, error } = await supabase
      .from('users')
      .select('*')
      .order('number', { ascending: true });
    if (error) throw error;
    return data || [];
  },

  verifyUser: async (params: { name: string; grade: number; class: number; number: number; role: string }): Promise<User | null> => {
    const { data, error } = await supabase
      .from('users')
      .select('*')
      .eq('name', params.name)
      .eq('grade', params.grade)
      .eq('class', params.class)
      .eq('number', params.number)
      .eq('role', params.role)
      .maybeSingle();
    if (error) throw error;
    return data;
  },

  verifyTeacherPassword: async (name: string, password: string): Promise<User | null> => {
    const { data, error } = await supabase.functions.invoke('auth-teacher', {
      body: { name, password }
    });
    if (error) return null;
    return data?.user || null;
  },

  ensureStudentInitialized: async (user: User) => {
    if (user.role !== 'student') return;
    const { data: acc } = await supabase.from('accounts').select('*').eq('userId', user.userId).maybeSingle();
    if (!acc) {
      await supabase.from('accounts').insert({
        accountId: `acc_${user.userId}`,
        userId: user.userId,
        balance: 10
      });
    }
    const { data: usage } = await supabase.from('news_ai_usage').select('*').eq('userId', user.userId).maybeSingle();
    if (!usage) {
      await supabase.from('news_ai_usage').insert({
        userId: user.userId,
        free_usage_count: 1,
        last_reset_date: new Date().toISOString()
      });
    }
  },

  getArticles: async (): Promise<NewsArticle[]> => {
    const { data, error } = await supabase.from('news_articles').select('*').order('created_at', { ascending: false });
    if (error) throw error;
    return (data || []).map(article => ({
      ...article,
      keywords: Array.isArray(article.keywords) ? article.keywords : (article.keywords || "").split(',')
    }));
  },

  addArticle: async (article: any): Promise<NewsArticle> => {
    const { data, error } = await supabase.from('news_articles').insert(article).select().single();
    if (error) throw error;
    return data;
  },

  approveArticle: async (articleId: string) => {
    await supabase.from('news_articles').update({ is_approved: true }).eq('id', articleId);
  },

  resetArticles: async () => {
    await supabase.rpc('reset_approved_articles_with_comments');
  },

  deleteArticle: async (articleId: string) => {
    await supabase.rpc('delete_article_with_comments', { target_article_id: articleId });
  },

  getComments: async (articleId?: string): Promise<NewsComment[]> => {
    let query = supabase.from('news_comments').select('*').order('created_at', { ascending: false });
    if (articleId) query = query.eq('article_id', articleId);
    const { data, error } = await query;
    if (error) throw error;
    return data || [];
  },

  addComment: async (comment: NewsComment) => {
    await supabase.from('news_comments').insert(comment);
  },

  getAccount: async (userId: string): Promise<Account | undefined> => {
    const { data, error } = await supabase.from('accounts').select('*').eq('userId', userId).maybeSingle();
    if (error) throw error;
    return data || undefined;
  },

  updateBalance: async (userId: string, amount: number) => {
    const { data: account } = await supabase.from('accounts').select('balance').eq('userId', userId).maybeSingle();
    if (account) {
      await supabase.from('accounts').update({ balance: Number(account.balance) + amount }).eq('userId', userId);
    }
  },

  getAiUsage: async (userId: string): Promise<NewsAiUsage | undefined> => {
    const { data, error } = await supabase.from('news_ai_usage').select('*').eq('userId', userId).maybeSingle();
    if (error) throw error;
    return data || undefined;
  },

  useAi: async (userId: string) => {
    const usage = await db.getAiUsage(userId);
    if (usage) {
      if (usage.free_usage_count > 0) {
        await supabase.from('news_ai_usage').update({ free_usage_count: usage.free_usage_count - 1 }).eq('userId', userId);
      } else {
        await db.updateBalance(userId, -3);
      }
    }
  }
};

import React, { useState, useEffect, useMemo } from 'react';
import { db } from '../services/storage.ts';
import { geminiService } from '../services/gemini.ts';
import { newsApiService } from '../services/newsApi.ts';
import { NewsArticle, NewsComment, User } from '../types.ts';

const TeacherDashboard: React.FC = () => {
  const [articles, setArticles] = useState<NewsArticle[]>([]);
  const [comments, setComments] = useState<NewsComment[]>([]);
  const [users, setUsers] = useState<User[]>([]);
  const [loading, setLoading] = useState(true);

  const [recommendedNews, setRecommendedNews] = useState<any[]>([]);
  const [isRecommending, setIsRecommending] = useState(false);
  const [selectedArticleDetail, setSelectedArticleDetail] = useState<any>(null);
  const [selectedArticleComments, setSelectedArticleComments] = useState<{title: string, comments: NewsComment[]} | null>(null);

  // 직접 올리기 및 수정 관련 상태
  const [isDirectUploadOpen, setIsDirectUploadOpen] = useState(false);
  const [directTitle, setDirectTitle] = useState('');
  const [directContent, setDirectContent] = useState('');

  const [isEditingDetail, setIsEditingDetail] = useState(false);
  const [editTitle, setEditTitle] = useState('');
  const [editContent, setEditContent] = useState('');

  const [resetConfirmOpen, setResetConfirmOpen] = useState(false);
  const [deletingArticleId, setDeletingArticleId] = useState<string | null>(null);

  const [baseDate, setBaseDate] = useState(() => {
    const d = new Date();
    d.setHours(0, 0, 0, 0);
    const day = d.getDay();
    const diff = d.getDate() - day + (day === 0 ? -6 : 1);
    d.setDate(diff);
    return d;
  });

  const [selectedStudentComments, setSelectedStudentComments] = useState<{name: string, userId: string} | null>(null);
  const [studentCommentsLimit, setStudentCommentsLimit] = useState(10);

  const loadData = async () => {
    setLoading(true);
    try {
      const [arts, comms, usrs] = await Promise.all([
        db.getArticles(),
        db.getComments(),
        db.getUsers()
      ]);
      setArticles(arts);
      setComments(comms);
      setUsers(usrs.filter(u => u.role === 'student'));
    } catch (err) {
      console.error("데이터 로드 실패:", err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadData();
  }, []);

  const handleFetchAiNews = async () => {
    setIsRecommending(true);
    try {
      const rawResults = await newsApiService.searchNews('경제 금융 뉴스');
      if (!rawResults || rawResults.length === 0) {
        alert('뉴스를 찾지 못했습니다.');
        return;
      }
      const curatedNews = await geminiService.recommendNews(rawResults);
      setRecommendedNews(curatedNews);
    } catch (err) {
      console.error(err);
      alert('오류가 발생했습니다.');
    } finally {
      setIsRecommending(false);
    }
  };

  const handleApprove = async (newsItem: any) => {
    try {
      await db.addArticle({
        title: newsItem.title,
        content: newsItem.content,
        url: newsItem.url || '',
        keywords: newsItem.keywords || ['경제', '금융'],
        is_approved: true
      });
      alert('승인되었습니다!');
      setRecommendedNews(prev => prev.filter(n => n.title !== newsItem.title));
      loadData();
    } catch (err: any) {
      console.error("승인 중 오류 발생:", err);
      alert('승인 중 오류가 발생했습니다.');
    }
  };

  const handleDirectUpload = async () => {
    if (!directTitle.trim() || !directContent.trim()) {
      alert('제목과 내용을 모두 입력해주세요.');
      return;
    }
    try {
      await db.addArticle({
        title: directTitle,
        content: directContent,
        url: '',
        keywords: ['직접입력', '경제'],
        is_approved: true
      });
      alert('기사가 성공적으로 등록되었습니다.');
      setIsDirectUploadOpen(false);
      setDirectTitle('');
      setDirectContent('');
      loadData();
    } catch (err) {
      console.error(err);
      alert('기사 등록 중 오류가 발생했습니다.');
    }
  };

  const startEditing = () => {
    setEditTitle(selectedArticleDetail.title);
    setEditContent(selectedArticleDetail.content);
    setIsEditingDetail(true);
  };

  const handleSaveEdit = async () => {
    if (!editTitle.trim() || !editContent.trim()) {
      alert('제목과 내용을 입력해주세요.');
      return;
    }

    try {
      // 1. 이미 승인되어 ID가 있는 기사인 경우 (DB 업데이트)
      if (selectedArticleDetail.id) {
        const { error } = await (db as any).supabase
          .from('news_articles')
          .update({ title: editTitle, content: editContent })
          .eq('id', selectedArticleDetail.id);

        if (error) throw error;
        alert('기사가 수정되었습니다.');
      } 
      // 2. 실시간 불러온 뉴스(미승인)인 경우 (로컬 상태 업데이트)
      else {
        setRecommendedNews(prev => prev.map(n => 
          n.title === selectedArticleDetail.title ? { ...n, title: editTitle, content: editContent } : n
        ));
        alert('화면의 뉴스 내용이 수정되었습니다. [승인 및 공개] 버튼을 누르면 저장됩니다.');
      }

      setSelectedArticleDetail({ ...selectedArticleDetail, title: editTitle, content: editContent });
      setIsEditingDetail(false);
      loadData();
    } catch (err) {
      console.error(err);
      alert('수정 중 오류가 발생했습니다.');
    }
  };

  const confirmResetArticles = async () => {
    try {
      await db.resetArticles();
      alert('초기화되었습니다.');
      setResetConfirmOpen(false);
      loadData();
    } catch (err) {
      console.error(err);
      alert('초기화 중 오류 발생');
    }
  };

  const confirmDeleteArticle = async () => {
    if (!deletingArticleId) return;
    try {
      await db.deleteArticle(deletingArticleId);
      alert('삭제되었습니다.');
      setDeletingArticleId(null);
      loadData();
    } catch (err) {
      console.error(err);
      alert('삭제 중 오류 발생');
    }
  };

  const weekRange = useMemo(() => {
    const start = new Date(baseDate);
    const end = new Date(baseDate);
    end.setDate(end.getDate() + 6);
    end.setHours(23, 59, 59, 999);
    return { start, end };
  }, [baseDate]);

  const changeWeek = (offset: number) => {
    const next = new Date(baseDate);
    next.setDate(next.getDate() + (offset * 7));
    setBaseDate(next);
  };

  const weeklyComments = useMemo(() => {
    return comments.filter(c => {
      const date = new Date(c.created_at);
      return date >= weekRange.start && date <= weekRange.end;
    });
  }, [comments, weekRange]);

  const approvedArticles = articles.filter(a => a.is_approved);

  const currentStudentComments = useMemo(() => {
    if (!selectedStudentComments) return [];
    return comments
      .filter(c => c.userId === selectedStudentComments.userId)
      .slice(0, studentCommentsLimit);
  }, [selectedStudentComments, studentCommentsLimit, comments]);

  const totalStudentCommentsCount = useMemo(() => {
    if (!selectedStudentComments) return 0;
    return comments.filter(c => c.userId === selectedStudentComments.userId).length;
  }, [selectedStudentComments, comments]);

  if (loading) return <div className="text-center py-20 font-kids text-xl">로딩 중... 📊</div>;

  return (
    <div className="max-w-7xl mx-auto p-6 space-y-12">
      <section className="bg-white rounded-3xl p-8 shadow-sm border-2 border-yellow-200">
        <div className="flex flex-col md:flex-row justify-between items-center mb-8 gap-4">
          <div>
            <h2 className="text-3xl font-kids text-yellow-600 mb-1">🗞️ 리얼 뉴스 큐레이션</h2>
            <p className="text-gray-500 text-sm">실제 뉴스를 아이들 눈높이로 다듬어줍니다.</p>
          </div>
          <div className="flex gap-3">
            <button 
              onClick={() => setIsDirectUploadOpen(true)}
              className="px-6 py-4 bg-white border-2 border-yellow-400 text-yellow-600 font-bold rounded-2xl hover:bg-yellow-50 transition-all shadow-md flex items-center gap-2"
            >
              <span className="text-xl">✍️</span>
              직접 기사 올리기
            </button>
            <button 
              onClick={handleFetchAiNews}
              disabled={isRecommending}
              className="px-8 py-4 bg-yellow-400 text-yellow-900 font-bold rounded-2xl hover:bg-yellow-500 transition-all shadow-lg disabled:opacity-50 flex items-center gap-3"
            >
              {isRecommending ? <span className="animate-spin text-xl">⏳</span> : <span className="text-xl">🔍</span>}
