                  }}
                  className={`w-full py-1.5 rounded-xl text-xs font-bold ${
                    studentComms.length > 0 ? 'bg-green-500 text-white' : 'bg-slate-100 text-slate-400'
                  }`}
                >
                  댓글 {studentComms.length}개
                </button>
              </div>
            );
          })}
        </div>
      </section>
    </div>
  );
};

export default TeacherDashboard;

