import { serve } from "https://deno.land/std@0.168.0/http/server.ts"
import { createClient } from 'https://esm.sh/@supabase/supabase-js@2.45.0'

const corsHeaders = {
  'Access-Control-Allow-Origin': '*',
  'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
}

serve(async (req) => {
  if (req.method === 'OPTIONS') {
    return new Response('ok', { headers: corsHeaders })
  }

  try {
    const { name, password } = await req.json()

    const supabaseUrl = (globalThis as any).Deno.env.get("SUPABASE_URL");
    const supabaseKey = (globalThis as any).Deno.env.get("SUPABASE_SERVICE_ROLE_KEY");

    if (!supabaseUrl || !supabaseKey) {
      throw new Error("서버 설정(SUPABASE_URL, SUPABASE_SERVICE_ROLE_KEY)이 누락되었습니다.");
    }

    const supabase = createClient(supabaseUrl, supabaseKey);

    // 1단계: RPC(check_teacher_password)를 호출하여 암호화된 비밀번호 검증
    const { data: authData, error: authError } = await supabase.rpc('check_teacher_password', {
      p_login_id: name,
      p_password: password
    });

    if (authError) throw authError;

    const teacher = authData && authData.length > 0 ? authData[0] : null;

    if (!teacher) {
      return new Response(
        JSON.stringify({ success: false, error: "아이디 또는 비밀번호가 틀렸습니다." }),
        { 
          headers: { ...corsHeaders, "Content-Type": "application/json" },
          status: 200 
        }
      )
    }

    // 2단계: teachers 테이블에서 teacherAlias 정보를 가져옴 (요청 3 반영)
    // users.userId(TEXT)가 teachers.id(UUID)와 연결됨을 확인
    const { data: teacherRecord, error: teacherInfoError } = await supabase
      .from('teachers')
      .select('teacherAlias')
      .eq('id', teacher.id)
      .maybeSingle();

    if (teacherInfoError) throw teacherInfoError;

    // 3단계: teachers.id(UUID)와 일치하는 users.userId(TEXT) 정보를 가져옴
    const { data: userProfile, error: profileError } = await supabase
      .from('users')
      .select('*')
      .eq('userId', teacher.id)
      .maybeSingle();

    if (profileError) throw profileError;

    if (!userProfile) {
      return new Response(
        JSON.stringify({ success: false, error: "교사 인증은 성공했으나, users 테이블에 연결된 프로필 정보가 없습니다." }),
        { 
          headers: { ...corsHeaders, "Content-Type": "application/json" },
          status: 200 
        }
      )
    }

    // 교사 별칭(teacherAlias)이 있다면 userProfile.name을 해당 별칭으로 강제 교체 (요청 3 반영)
    if (teacherRecord && teacherRecord.teacherAlias) {
      userProfile.name = teacherRecord.teacherAlias;
    }

    return new Response(
      JSON.stringify({ success: true, user: userProfile }),
      { 
        headers: { ...corsHeaders, "Content-Type": "application/json" },
        status: 200 
      }
    )
  } catch (error: any) {
    console.error("Auth Teacher Error:", error.message);
    return new Response(
      JSON.stringify({ success: false, error: error.message }),
      { 
        headers: { ...corsHeaders, "Content-Type": "application/json" },
        status: 400 
      }
    )
  }
})

import React, { useState } from 'react';
import { User, UserRole } from '../types.ts';
import { db } from '../services/storage.ts';

interface LoginViewProps {
  onLogin: (user: User) => Promise<void>;
}

const LoginView: React.FC<LoginViewProps> = ({ onLogin }) => {
  const [role, setRole] = useState<UserRole>('student');
  const [name, setName] = useState('');
  const [grade, setGrade] = useState(6);
  const [classNum, setClassNum] = useState(1);
  const [number, setNumber] = useState(1);
  const [password, setPassword] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [loginError, setLoginError] = useState<string | null>(null);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (isSubmitting) return;

    setLoginError(null);
    setIsSubmitting(true);
    try {
      if (role === 'teacher') {
        if (!name.trim()) {
          setLoginError('선생님 아이디를 입력해주세요!');
          setIsSubmitting(false);
          return;
        }

        const teacherUser = await db.verifyTeacherPassword(name, password);

        if (teacherUser) {
          await onLogin(teacherUser);
        } else {
          // 교사 로그인 실패 메시지 표시 (요청 1 반영)
          setLoginError('아이디(이메일)나 비밀번호를 다시 확인해주세요.');
        }
      } else {
        if (!name.trim()) {
          alert('이름을 입력해주세요!');
          setIsSubmitting(false);
          return;
        }

        const verifiedUser = await db.verifyUser({
          name,
          grade,
          class: classNum,
          number,
          role: 'student'
        });

        if (verifiedUser) {
          await onLogin(verifiedUser);
        } else {
          alert('학생 정보를 다시 확인해주세요.');
        }
      }
    } catch (err: any) {
      console.error("Login verification error:", err);
      setLoginError("로그인 확인 중 오류가 발생했습니다. 잠시 후 다시 시도해주세요.");
    } finally {
      setIsSubmitting(false);
    }
  };

