import { serve } from "https://deno.land/std@0.168.0/http/server.ts"
import { createClient } from 'https://esm.sh/@supabase/supabase-js@2.45.0'

const corsHeaders = {
  'Access-Control-Allow-Origin': '*',
  'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
}

serve(async (req) => {
  if (req.method === 'OPTIONS') {
    return new Response('ok', { headers: corsHeaders })
  }

  try {
    const { name, password } = await req.json()

    const supabaseUrl = (globalThis as any).Deno.env.get("SUPABASE_URL");
    const supabaseKey = (globalThis as any).Deno.env.get("SUPABASE_SERVICE_ROLE_KEY");

    if (!supabaseUrl || !supabaseKey) {
      throw new Error("서버 설정(SUPABASE_URL, SUPABASE_SERVICE_ROLE_KEY)이 누락되었습니다.");
    }

    const supabase = createClient(supabaseUrl, supabaseKey);

    // 1단계: RPC(check_teacher_password)를 호출하여 암호화된 비밀번호 검증
    const { data: authData, error: authError } = await supabase.rpc('check_teacher_password', {
      p_login_id: name,
      p_password: password
    });

    if (authError) throw authError;

    // authData는 보통 배열로 반환됨
    const teacherResult = authData && authData.length > 0 ? authData[0] : null;

    if (!teacherResult || !teacherResult.id) {
      return new Response(
        JSON.stringify({ success: false, error: "아이디 또는 비밀번호가 틀렸습니다." }),
        { 
          headers: { ...corsHeaders, "Content-Type": "application/json" },
          status: 200 
        }
      )
    }

    const teacherUuid = teacherResult.id;

    // 2단계: teachers 테이블에서 teacherAlias 정보를 가져옴 (요청 3 반영)
    const { data: teacherRecord, error: teacherInfoError } = await supabase
      .from('teachers')
      .select('teacherAlias')
      .eq('id', teacherUuid)
      .maybeSingle();

    if (teacherInfoError) console.error("Teacher Alias Fetch Error:", teacherInfoError);

    // 3단계: UUID를 문자열로 변환하여 users.userId(TEXT)와 매칭 시도
    const { data: userProfile, error: profileError } = await supabase
      .from('users')
      .select('*')
      .eq('userId', String(teacherUuid))
      .maybeSingle();

    if (profileError) throw profileError;

    if (!userProfile) {
      return new Response(
        JSON.stringify({ success: false, error: "교사 계정은 확인되었으나, 연결된 사용자 프로필을 찾을 수 없습니다." }),
        { 
          headers: { ...corsHeaders, "Content-Type": "application/json" },
          status: 200 
        }
      )
    }

    // 교사 별칭(teacherAlias)이 있다면 userProfile.name을 해당 별칭으로 교체 (요청 2 반영)
    if (teacherRecord && teacherRecord.teacherAlias && teacherRecord.teacherAlias.trim() !== "") {
      userProfile.name = teacherRecord.teacherAlias;
    }

    return new Response(
      JSON.stringify({ success: true, user: userProfile }),
      { 
        headers: { ...corsHeaders, "Content-Type": "application/json" },
        status: 200 
      }
    )
  } catch (error: any) {
    console.error("Auth Teacher Error:", error.message);
    return new Response(
      JSON.stringify({ success: false, error: error.message }),
      { 
        headers: { ...corsHeaders, "Content-Type": "application/json" },
        status: 400 
      }
    )
  }
})

import React, { useState, useEffect } from 'react';
import { User, Account, NewsAiUsage } from './types.ts';
import { db } from './services/storage.ts';
import Header from './components/Header.tsx';
import LoginView from './views/LoginView.tsx';
import StudentDashboard from './views/StudentDashboard.tsx';
import TeacherDashboard from './views/TeacherDashboard.tsx';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [account, setAccount] = useState<Account | undefined>();
  const [aiUsage, setAiUsage] = useState<NewsAiUsage | undefined>();
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const initApp = async () => {
      try {
        const user = db.getCurrentUser();
        if (user) {
          setCurrentUser(user);
          await refreshData(user);
        }
      } catch (err) {
        console.error("초기화 오류:", err);
      } finally {
        setLoading(false);
      }
    };
    initApp();
  }, []);

  const refreshData = async (user: User) => {
    if (user.role === 'student') {
      try {
        const [acc, usage] = await Promise.all([
          db.getAccount(user.userId),
          db.getAiUsage(user.userId)
        ]);
        setAccount(acc);
        setAiUsage(usage);
      } catch (err) {
        console.warn("데이터 로드 실패:", err);
      }
    }
  };

  const handleLogin = async (user: User) => {
    setLoading(true);
    try {
      if (user.role === 'student') {
        await db.ensureStudentInitialized(user);
      }
      setCurrentUser(user);
      db.setCurrentUser(user);
      await refreshData(user);
    } catch (err: any) {
      alert(`오류가 발생했습니다: ${err.message}`);
    } finally {
      setLoading(false);
    }
  };

  const handleLogout = () => {
    setCurrentUser(null);
    db.setCurrentUser(null);
    setAccount(undefined);
    setAiUsage(undefined);
  };

  if (loading) return (
    <div className="min-h-screen flex items-center justify-center font-kids text-2xl flex-col gap-4 bg-blue-50">
      <div className="animate-bounce text-6xl">🚀</div>
      <div className="text-blue-600">데이터를 불러오는 중...</div>
    </div>
  );

  if (!currentUser) {
    return <LoginView onLogin={handleLogin} />;
  }

  return (
    <div className="min-h-screen flex flex-col bg-blue-50/30">
      <Header 
        user={currentUser} 
        account={account} 
        aiUsage={aiUsage}
        onLogout={handleLogout} 
      />

      <main className="max-w-6xl mx-auto flex-1 w-full">
        {currentUser.role === 'teacher' ? (
          <TeacherDashboard />
        ) : (
          <StudentDashboard user={currentUser} onUpdate={() => refreshData(currentUser)} />
        )}
      </main>

      {/* 푸터 영역: 저작권 문구 추가 (요청 3 반영) */}
      <footer className="w-full py-8 text-center text-gray-400 text-xs font-medium border-t border-gray-100 mt-12 bg-white/50">
        ⓒ 2026. Kwon's class. All rights reserved.
      </footer>
    </div>
  );
};

export default App;

